-- ============================================
-- GROUP 1: NAMES & TITLES OF GOD (IDs 25–29)
-- ============================================

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  25, 1, 'vocabulary', 'θεός — God', 'G2316 · 1,317 occurrences · The primary name for God',
  '{"word":"θεός","transliteration":"theos","meaning":"God","part_of_speech":"Noun, masculine","strongs":"G2316","numeric_occurrences":1317,"etymology":"Related to the Proto-Indo-European root dhēs meaning divine. Greeks used it for any deity; the NT writers use it overwhelmingly for the one true God of Israel.","theological_significance":"The most common word for God in the NT appearing 1317 times. Used for all three persons of the Trinity. NT writers also use it to affirm Jesus as divine (John 1:1, John 20:28, Titus 2:13). The compound Immanuel means God (El) with us.","related_words":["θεότης (theotēs, G2320) — deity, the fullness of divine nature (Col 2:9)","θεῖος (theios, G2304) — divine (2 Pet 1:3–4)","θεόπνευστος (theopneustos, G2315) — God-breathed (2 Tim 3:16)"],"practice":[{"type":"identify","question":"What does θεός (theos) mean?","answer":"God"},{"type":"choice","question":"How many times does θεός appear in the New Testament?","options":["About 500","About 900","About 1,317","About 2,100"],"answer":2},{"type":"choice","question":"In John 20:28, Thomas declares My Lord and my God! The word God is θεός. Who is Thomas calling θεός?","options":["God the Father only","Jesus","The Holy Spirit","An angel"],"answer":1}]}',
  '[{"ref":"John 1:1","text":"In the beginning was the Word, and the Word was with God, and the Word was God","note":"θεός appears twice — once for the Father (with God) and once as a predicate for Christ (was God). The most contested and profound theological claim of the NT"},{"ref":"1 John 4:8","text":"He that loveth not knoweth not God; for God is love","note":"θεός ἐστιν ἀγάπη — God IS love. Not merely that God loves, but that love is His very nature. θεός defines ἀγάπη and ἀγάπη defines θεός"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  26, 2, 'vocabulary', 'κύριος — Lord', 'G2962 · 748 occurrences · The earliest Christian confession',
  '{"word":"κύριος","transliteration":"kyrios","meaning":"Lord / Master / Owner","part_of_speech":"Noun, masculine","strongs":"G2962","numeric_occurrences":748,"etymology":"From kyros meaning authority or power. In the Septuagint (Greek OT), κύριος translates the divine name YHWH — so when NT authors call Jesus κύριος they are making an unmistakable claim to His deity.","theological_significance":"The earliest Christian creed was three words: κύριος Ἰησοῦς — Jesus is Lord (Rom 10:9). By applying the Septuagint''s translation of YHWH (κύριος) to Jesus, the NT writers declare His full divinity. Phil 2:9-11 uses Isa 45:23 (an YHWH passage) to proclaim Jesus as κύριος.","related_words":["κυριεύω (kyrieuō, G2961) — to be lord over, to rule","κυριότης (kyriotēs, G2963) — lordship, dominion"],"practice":[{"type":"identify","question":"What does κύριος (kyrios) mean?","answer":"Lord"},{"type":"choice","question":"The earliest Christian confession was κύριος Ἰησοῦς — what does this mean?","options":["Jesus saves","Jesus is Lord","Jesus is God","Jesus is King"],"answer":1},{"type":"choice","question":"In the Greek OT (Septuagint), κύριος translates which Hebrew divine name?","options":["Elohim","El Shaddai","YHWH (the LORD)","Adonai"],"answer":2}]}',
  '[{"ref":"Romans 10:9","text":"That if thou shalt confess with thy mouth the Lord Jesus, and shalt believe in thine heart that God hath raised him from the dead, thou shalt be saved","note":"κύριος Ἰησοῦς — the saving confession. Paul links the mouth-confession of Christ''s Lordship with heart-belief in His resurrection"},{"ref":"Philippians 2:11","text":"And that every tongue should confess that Jesus Christ is Lord, to the glory of God the Father","note":"The cosmic conclusion: every tongue will confess κύριος — the name above every name applied to Jesus. Quoting Isaiah 45:23 (an YHWH passage) and applying it to Christ"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  27, 3, 'vocabulary', 'Χριστός — Christ', 'G5547 · 569 occurrences · The Anointed One',
  '{"word":"Χριστός","transliteration":"Christos","meaning":"Christ / the Anointed One / Messiah","part_of_speech":"Noun, masculine","strongs":"G5547","numeric_occurrences":569,"etymology":"The Greek translation of the Hebrew Mashiach (Messiah). Christos comes from chriō meaning to anoint — used when oil was poured over a king, priest, or prophet to consecrate them. Jesus is the ultimate fulfilment of all three roles: Prophet, Priest, and King.","theological_significance":"Originally used as a title (the Christ = the Messiah) it quickly became part of Jesus'' personal name (Jesus Christ). The entire OT pointed toward the Χριστός. When Peter confesses Thou art the Christ (Matt 16:16), he uses this word. The X in Xmas is Chi — the first letter of Χριστός.","related_words":["χρίω (chriō, G5548) — to anoint (Luke 4:18, Acts 10:38)","ἀντίχριστος (antichristos, G500) — antichrist, one opposing the anointed (1 John 2:18)"],"practice":[{"type":"identify","question":"What does Χριστός (Christos) mean?","answer":"The Anointed One / Christ / Messiah"},{"type":"choice","question":"Χριστός is the Greek translation of which Hebrew word?","options":["Shalom","Elohim","Mashiach (Messiah)","Adonai"],"answer":2},{"type":"choice","question":"The word Christos comes from chriō meaning to anoint. In the OT, who was anointed with oil?","options":["Kings only","Priests only","Prophets only","Kings, Priests, and Prophets — all three roles Jesus fulfils"],"answer":3}]}',
  '[{"ref":"Matthew 16:16","text":"And Simon Peter answered and said, Thou art the Christ, the Son of the living God","note":"Peter''s great confession: σὺ εἶ ὁ Χριστός — You are the Anointed One. Jesus calls this revelation a foundation stone of the church"},{"ref":"Acts 2:36","text":"Therefore let all the house of Israel know assuredly, that God hath made that same Jesus, whom ye have crucified, both Lord and Christ","note":"κύριον καὶ Χριστόν — Lord AND Christ. Peter''s Pentecost declaration combining both great titles for the risen Jesus"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  28, 4, 'vocabulary', 'Ἰησοῦς — Jesus', 'G2424 · 975 occurrences · God saves',
  '{"word":"Ἰησοῦς","transliteration":"Iēsous","meaning":"Jesus (Hebrew: Yeshua — God saves / the LORD is salvation)","part_of_speech":"Noun, masculine (proper name)","strongs":"G2424","numeric_occurrences":975,"etymology":"Greek form of the Hebrew Yehoshua (Joshua) meaning YHWH saves. The angel commanded this specific name: thou shalt call his name JESUS: for he shall save his people from their sins (Matt 1:21). The name is itself a declaration of His mission.","theological_significance":"The most frequent proper name in the NT at 975 occurrences. His name is literally salvation — every time someone called His name they were proclaiming the gospel. There is no other name under heaven given among men, whereby we must be saved (Acts 4:12). The name above every name (Phil 2:9).","related_words":["σωτήρ (sōtēr, G4990) — Saviour, the one who saves","σωτηρία (sōtēria, G4991) — salvation, the act and result of saving"],"practice":[{"type":"identify","question":"What does the name Ἰησοῦς (Iēsous / Jesus) mean in Hebrew?","answer":"God saves / YHWH is salvation"},{"type":"choice","question":"The name Jesus (Ἰησοῦς) is the Greek form of which Hebrew name?","options":["David","Moses","Joshua (Yehoshua)","Elijah"],"answer":2},{"type":"choice","question":"The angel told Mary and Joseph to name the child Jesus. Why?","options":["It was a family name","For he shall save his people from their sins","It means anointed king","It means God with us"],"answer":1}]}',
  '[{"ref":"Matthew 1:21","text":"And she shall bring forth a son, and thou shalt call his name JESUS: for he shall save his people from their sins","note":"The name Ἰησοῦς is given with its meaning attached. His identity and His mission are fused into one name — God saves"},{"ref":"Acts 4:12","text":"Neither is there salvation in any other: for there is none other name under heaven given among men, whereby we must be saved","note":"The name (ὄνομα) of Ἰησοῦς is the only vehicle of salvation. Exclusivity rooted not in arrogance but in the uniqueness of God incarnate"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  29, 5, 'vocabulary', 'πνεῦμα — Spirit', 'G4151 · 385 occurrences · Breath, Wind & Spirit',
  '{"word":"πνεῦμα","transliteration":"pneuma","meaning":"Spirit / breath / wind","part_of_speech":"Noun, neuter","strongs":"G4151","numeric_occurrences":385,"etymology":"From pneō meaning to breathe or to blow. The same word covers the physical breath, the wind, the human spirit, and the Holy Spirit — because the biblical authors see all of these as interconnected. God breathed (enephysēsen) into Adam and he became a living soul (Gen 2:7 LXX). Our words pneumatic and pneumonia come from this root.","theological_significance":"Used 385 times in the NT — for the Holy Spirit, for human spirits, for evil spirits, and for breath/wind (John 3:8). The pneuma is the animating, life-giving principle that connects the human to the divine. Crucially, God is Spirit (πνεῦμα ὁ θεός, John 4:24) — not bound by physical form.","related_words":["πνευματικός (pneumatikos, G4152) — spiritual (1 Cor 2:14–15)","πνέω (pneō, G4154) — to blow, to breathe"],"practice":[{"type":"identify","question":"What does πνεῦμα (pneuma) mean?","answer":"Spirit / breath / wind"},{"type":"choice","question":"In John 3:8 Jesus says the wind (πνεῦμα) blows where it will — He is using this as a picture of what?","options":["The weather","The Holy Spirit","Human breath","Angels"],"answer":1},{"type":"choice","question":"Our English medical word pneumonia comes from πνεῦμα. What does it relate to?","options":["The heart","The lungs / breathing","The blood","The brain"],"answer":1}]}',
  '[{"ref":"John 4:24","text":"God is a Spirit: and they that worship him must worship him in spirit and in truth","note":"πνεῦμα ὁ θεός — God is Spirit. This declaration shapes all true worship: not tied to a mountain or a temple but to the Spirit and truth"},{"ref":"Acts 2:2–4","text":"And suddenly there came a sound from heaven as of a rushing mighty wind...And they were all filled with the Holy Ghost","note":"The wind (πνοή, from same root as πνεῦμα) and the Spirit come together at Pentecost. The breath of God fills His people just as He breathed life into Adam"}]'
);

-- ============================================
-- GROUP 2: SALVATION WORDS (IDs 30–34)
-- ============================================

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  30, 6, 'vocabulary', 'ἀγάπη — Love', 'G26 · 116 occurrences · The highest love',
  '{"word":"ἀγάπη","transliteration":"agapē","meaning":"Unconditional love / self-giving love","part_of_speech":"Noun, feminine","strongs":"G26","numeric_occurrences":116,"etymology":"Rarely used in classical Greek before the NT. The NT writers essentially redefined and elevated this word to describe a uniquely divine love. Greek also had eros (passionate desire) and philia (friendship/affection) — agapē is the love that gives regardless of the worth of the recipient.","theological_significance":"God IS ἀγάπη (1 John 4:8). The greatest commandment is to love (ἀγαπάω) God and neighbour (Matt 22:37-39). The love chapter (1 Cor 13) defines ἀγάπη by what it does and does not do. John 3:16 is the ἀγάπη of God in action — giving the most precious gift at the greatest cost for the least deserving.","related_words":["ἀγαπάω (agapaō, G25) — to love (verb form, 143×)","φιλέω (phileō, G5368) — to love as a friend / to have affection for (25×)","φιλαδελφία (philadelphia, G5360) — brotherly love (6×)"],"practice":[{"type":"identify","question":"What does ἀγάπη (agapē) mean?","answer":"Unconditional / self-giving love"},{"type":"choice","question":"1 John 4:8 says God is ___. Fill in the Greek word.","options":["δόξα (doxa, glory)","φῶς (phōs, light)","ἀγάπη (agapē, love)","ζωή (zōē, life)"],"answer":2},{"type":"choice","question":"Greek has three main words for love. Agapē is self-giving love. Philia is friendship. What is eros?","options":["Family love","Passionate / romantic desire","Parental love","Spiritual love"],"answer":1}]}',
  '[{"ref":"John 3:16","text":"For God so loved the world, that he gave his only begotten Son","note":"ἠγάπησεν — the verb form of ἀγάπη. God''s love is not a feeling but an action: He GAVE. The greatest definition of agapē is a cross."},{"ref":"1 Corinthians 13:4–7","text":"Charity suffereth long, and is kind; charity envieth not; charity vaunteth not itself","note":"Charity here is ἀγάπη. Paul''s entire description is active — agapē does things and refuses other things. It is a choice, not merely an emotion"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  31, 7, 'vocabulary', 'πίστις — Faith', 'G4102 · 244 occurrences · The foundation of salvation',
  '{"word":"πίστις","transliteration":"pistis","meaning":"Faith / trust / belief / faithfulness","part_of_speech":"Noun, feminine","strongs":"G4102","numeric_occurrences":244,"etymology":"From peithō meaning to persuade or to be convinced. Faith in the NT is not blind belief but a conviction that has been persuaded by evidence — the resurrection, the witness of Scripture, the testimony of changed lives.","theological_significance":"The central word of Paul''s theology. The just shall live by πίστις (Rom 1:17, Gal 3:11, Heb 10:38) — quoted from Habakkuk 2:4. We are saved through πίστις not works (Eph 2:8). The great faith chapter (Heb 11) defines πίστις as the substance of things hoped for — it has real substance. Also means faithfulness (as in God''s faithfulness).","related_words":["πιστεύω (pisteuō, G4100) — to believe, to trust (248×)","πιστός (pistos, G4103) — faithful, trustworthy (67×)","ἄπιστος (apistos, G571) — unbelieving, unfaithful (23×)"],"practice":[{"type":"identify","question":"What does πίστις (pistis) mean?","answer":"Faith / trust / faithfulness"},{"type":"choice","question":"Hebrews 11:1 defines πίστις as the ___ of things hoped for.","options":["Shadow","Substance / evidence","Feeling","Memory"],"answer":1},{"type":"choice","question":"Paul quotes Habakkuk 2:4 three times: The just shall live by ___. What word fills the blank?","options":["Works","Law","Faith (πίστις)","Grace"],"answer":2}]}',
  '[{"ref":"Ephesians 2:8","text":"For by grace are ye saved through faith; and that not of yourselves: it is the gift of God","note":"Saved (σεσῳσμένοι) through πίστις — faith is the channel, grace is the source. Both are gifts; neither is a human achievement"},{"ref":"Hebrews 11:1","text":"Now faith is the substance of things hoped for, the evidence of things not seen","note":"πίστις is ὑπόστασις (substance, title-deed) and ἔλεγχος (evidence, proof). Biblical faith is not feeling — it is the legal assurance of a future reality"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  32, 8, 'vocabulary', 'χάρις — Grace', 'G5485 · 156 occurrences · Undeserved favour',
  '{"word":"χάρις","transliteration":"charis","meaning":"Grace / undeserved favour / gift","part_of_speech":"Noun, feminine","strongs":"G5485","numeric_occurrences":156,"etymology":"From chairō meaning to rejoice, to be glad. Grace produces joy — both in the giver and receiver. The classical Greek sense was charm or attractiveness; the NT transforms it to mean unmerited divine favour given freely to the undeserving.","theological_significance":"The word that defines the NT age. Every Pauline letter opens and closes with χάρις. Grace is not merely forgiveness — it is the active, life-giving power of God working in and through believers (1 Cor 15:10). By grace we are saved (Eph 2:5,8). Grace and works are mutually exclusive as the basis of salvation (Rom 11:6).","related_words":["χαρίζομαι (charizomai, G5483) — to give freely, to forgive (23×)","χάρισμα (charisma, G5486) — gift of grace, spiritual gift (17×)","εὐχαριστία (eucharistia, G2169) — thanksgiving (15×, root of eucharist)"],"practice":[{"type":"identify","question":"What does χάρις (charis) mean?","answer":"Grace / undeserved favour"},{"type":"choice","question":"χάρισμα (charisma) comes from χάρις (grace). What does charisma mean in the NT?","options":["Natural talent","A gift of grace (spiritual gift)","A personality trait","A blessing"],"answer":1},{"type":"choice","question":"Paul says in Romans 11:6 that if salvation is by grace, it cannot be by ___. These two are mutually exclusive.","options":["Faith","Love","Works / human effort","Prayer"],"answer":2}]}',
  '[{"ref":"Ephesians 2:8–9","text":"For by grace are ye saved through faith; and that not of yourselves: it is the gift of God: not of works, lest any man should boast","note":"χάρις — the word that changes everything. Salvation is χάρις (grace) through πίστις (faith), not ἔργων (works). God''s undeserved gift cannot be earned"},{"ref":"John 1:17","text":"For the law was given by Moses, but grace and truth came by Jesus Christ","note":"χάρις καὶ ἀλήθεια — grace and truth together in the Person of Christ. The law defined the standard; grace provides the power to meet it through Christ"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  33, 9, 'vocabulary', 'σωτηρία — Salvation', 'G4991 · 46 occurrences · Deliverance & wholeness',
  '{"word":"σωτηρία","transliteration":"sōtēria","meaning":"Salvation / deliverance / wholeness / preservation","part_of_speech":"Noun, feminine","strongs":"G4991","numeric_occurrences":46,"etymology":"From sōzō (to save, to heal, to make whole) and sōtēr (saviour). The Greek concept included rescue from danger, healing of sickness, and political deliverance. The NT combines all these: Christ saves from sin (ultimate), heals the sick (temporal sign), and delivers from every enemy.","theological_significance":"The grand theme of the entire Bible. The Hebrew equivalent is Yeshua — which is the personal name of Jesus. Salvation in the NT has three tenses: we HAVE BEEN saved (justification, past), we ARE BEING saved (sanctification, present), we WILL BE saved (glorification, future). It is a complete rescue operation covering past guilt, present power, and future glory.","related_words":["σῴζω (sōzō, G4982) — to save, to heal, to rescue (106×)","σωτήρ (sōtēr, G4990) — Saviour (24×)","σωτήριος (sōtērios, G4992) — saving, bringing salvation (5×)"],"practice":[{"type":"identify","question":"What does σωτηρία (sōtēria) mean?","answer":"Salvation / deliverance"},{"type":"choice","question":"The name Jesus (Ἰησοῦς) comes from the Hebrew Yeshua which shares the same root as σωτηρία. What does this tell us about Jesus?","options":["He is a king","His very name declares His mission: salvation","He is a prophet","He is a priest only"],"answer":1},{"type":"choice","question":"Salvation (σωτηρία) in the NT has three tenses. Which is NOT one of them?","options":["Past: justified (saved from guilt)","Present: sanctified (saved from power of sin)","Middle: purified by suffering alone","Future: glorified (saved from presence of sin)"],"answer":2}]}',
  '[{"ref":"Acts 4:12","text":"Neither is there salvation in any other: for there is none other name under heaven given among men, whereby we must be saved","note":"σωτηρία is exclusive — one source, one name, one way. Not arrogance but the uniqueness of God''s own rescue plan in Christ"},{"ref":"Romans 1:16","text":"For I am not ashamed of the gospel of Christ: for it is the power of God unto salvation to every one that believeth","note":"σωτηρία is God''s δύναμις (power) unleashed — to the Jew first and also to the Greek. The gospel is the only sufficient power for complete salvation"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  34, 10, 'vocabulary', 'ἁμαρτία — Sin', 'G266 · 173 occurrences · Missing the mark',
  '{"word":"ἁμαρτία","transliteration":"hamartia","meaning":"Sin / missing the mark / moral failure","part_of_speech":"Noun, feminine","strongs":"G266","numeric_occurrences":173,"etymology":"From hamartenō meaning to miss the target — the word used in archery when an arrow misses its mark. Sin is not primarily rule-breaking but failing to hit God''s intended purpose and design for human life. It is falling short of the glory of God (Rom 3:23).","theological_significance":"The problem that makes salvation necessary. All have sinned (ἥμαρτον) and fall short of the glory of God (Rom 3:23). Sin entered through one man Adam (Rom 5:12). The solution is the Lamb of God who takes away the ἁμαρτία of the world (John 1:29). Christ was made ἁμαρτία for us (2 Cor 5:21) — the great exchange.","related_words":["ἁμαρτάνω (hamartanō, G264) — to sin, to miss the mark (43×)","ἁμαρτωλός (hamartōlos, G268) — sinner (47×)","παράπτωμα (paraptōma, G3900) — trespass, falling beside the path (19×)"],"practice":[{"type":"identify","question":"What does ἁμαρτία (hamartia) mean — and what image does it come from?","answer":"Sin — from the archery term meaning to miss the mark"},{"type":"choice","question":"Romans 3:23 says all have sinned and fall short of the ___ of God.","options":["Law","Love","Glory (δόξα)","Truth"],"answer":2},{"type":"choice","question":"In 2 Corinthians 5:21, Paul says God made Christ to be ἁμαρτία (sin) for us. What was the purpose?","options":["To punish Jesus","That we might become the righteousness of God in him","To satisfy the law only","To show God''s power"],"answer":1}]}',
  '[{"ref":"John 1:29","text":"Behold the Lamb of God, which taketh away the sin of the world","note":"ἁμαρτία τοῦ κόσμου — the sin of the world. Christ came to remove the entire weight of human moral failure from the record and from the soul"},{"ref":"1 John 1:9","text":"If we confess our sins, he is faithful and just to forgive us our sins, and to cleanse us from all unrighteousness","note":"ἁμαρτίας — sins. The promise is dual: forgiveness (legal standing) AND cleansing (inner reality). Both dimensions of the sin problem are addressed"}]'
);

-- ============================================
-- GROUP 3: CHURCH & COMMUNITY (IDs 35–39)
-- ============================================

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  35, 11, 'vocabulary', 'ἐκκλησία — Church', 'G1577 · 115 occurrences · The called-out assembly',
  '{"word":"ἐκκλησία","transliteration":"ekklēsia","meaning":"Church / assembly / congregation (the called-out ones)","part_of_speech":"Noun, feminine","strongs":"G1577","numeric_occurrences":115,"etymology":"From ek (out of) + kaleō (to call). In Greek civic life, the ekklēsia was the public assembly of citizens called out from their homes to conduct the city''s business. The NT takes this political term and fills it with spiritual meaning: the church is those called out of the world by God to conduct kingdom business.","theological_significance":"Jesus declared I will build my ἐκκλησία (Matt 16:18) — the only direct statement of Jesus about founding the church. The church is called out but also called together: not merely individual Christians but a covenant community. The church is the body of Christ (1 Cor 12:27), the bride of Christ (Eph 5:25-27), and the household of God (1 Tim 3:15).","related_words":["καλέω (kaleō, G2564) — to call (148×, root of ekklēsia)","κλητός (klētos, G2822) — called, invited (11×)","ἐκκλησιάζω — to assemble together"],"practice":[{"type":"identify","question":"What does ἐκκλησία (ekklēsia) mean?","answer":"Church / the called-out assembly"},{"type":"choice","question":"ἐκκλησία comes from ek (out) + kaleō (to call). What does this tell us about the church?","options":["It is a building","It is a group of people called out by God","It is a religious institution","It is a ceremony"],"answer":1},{"type":"choice","question":"Jesus said I will build my ἐκκλησία. What did He promise the gates of hell would not do?","options":["Tempt the church","Prevail against it / overcome it","Attack it","Ignore it"],"answer":1}]}',
  '[{"ref":"Matthew 16:18","text":"And I say also unto thee, That thou art Peter, and upon this rock I will build my church; and the gates of hell shall not prevail against it","note":"ἐκκλησία — the only direct statement of Jesus about founding the church. Built on the confession of Christ, against which no power of death can ultimately prevail"},{"ref":"Ephesians 5:25","text":"Husbands, love your wives, even as Christ also loved the church, and gave himself for it","note":"Christ''s love for the ἐκκλησία is the model for marriage. He gave Himself entirely — the ἐκκλησία is His bride, purchased with His own blood"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  36, 12, 'vocabulary', 'εὐαγγέλιον — Gospel', 'G2098 · 77 occurrences · Good news',
  '{"word":"εὐαγγέλιον","transliteration":"euangelion","meaning":"Gospel / good news / good message","part_of_speech":"Noun, neuter","strongs":"G2098","numeric_occurrences":77,"etymology":"From eu (good, well) + angelos (messenger). In the Roman world, euangelion was used for the announcement of a great victory in battle or the birth of an emperor. The NT hijacks this imperial term: the real euangelion is not Caesar''s victory but Christ''s — over sin, death, and hell.","theological_significance":"The content of the gospel: Christ died for our sins, was buried, and rose on the third day (1 Cor 15:3-4). Paul would not let it be distorted — if anyone preaches another euangelion, let him be accursed (Gal 1:8-9). Mark begins his account: The beginning of the euangelion of Jesus Christ, Son of God (Mark 1:1). Our words evangelist, evangelical, and evangelism all derive from this word.","related_words":["εὐαγγελίζω (euangelizō, G2097) — to preach the gospel (54×)","εὐαγγελιστής (euangelistēs, G2099) — evangelist (3×)"],"practice":[{"type":"identify","question":"What does εὐαγγέλιον (euangelion) mean?","answer":"Gospel / good news"},{"type":"choice","question":"Paul defines the core content of the euangelion in 1 Corinthians 15:3-4. Which best summarises it?","options":["Love God and neighbour","Christ died for our sins, was buried, and rose on the third day","Jesus is Lord and Saviour","Repent and be baptized"],"answer":1},{"type":"choice","question":"In the Roman world, euangelion was used for announcements of what?","options":["Temple festivals","Imperial victories or the emperor''s birth","Market prices","Legal verdicts"],"answer":1}]}',
  '[{"ref":"Mark 1:1","text":"The beginning of the gospel of Jesus Christ, the Son of God","note":"Mark launches straight in: ἀρχὴ τοῦ εὐαγγελίου. The entire Gospel of Mark is a euangelion — good news about who Jesus is and what He has done"},{"ref":"1 Corinthians 15:3–4","text":"For I delivered unto you first of all that which I also received, how that Christ died for our sins according to the scriptures; And that he was buried, and that he rose again the third day","note":"Paul''s compact definition of the εὐαγγέλιον: death, burial, resurrection. The three historical facts on which all Christian hope rests"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  37, 13, 'vocabulary', 'κοινωνία — Fellowship', 'G2842 · 20 occurrences · Shared life',
  '{"word":"κοινωνία","transliteration":"koinōnia","meaning":"Fellowship / participation / sharing / partnership","part_of_speech":"Noun, feminine","strongs":"G2842","numeric_occurrences":20,"etymology":"From koinos meaning common — the shared, the communal. Koinōnia is much richer than the English word fellowship (which often just means socialising). It means sharing in something together: sharing in Christ, sharing in the Spirit, sharing in suffering, sharing in ministry.","theological_significance":"The early church devoted itself to the apostles'' teaching and to koinōnia (Acts 2:42). We have κοινωνία with the Father and with His Son Jesus Christ (1 John 1:3). The Lord''s Supper is the κοινωνία of the blood and body of Christ (1 Cor 10:16). Paul calls his partnership with the Philippians a κοινωνία in the gospel (Phil 1:5). It is shared life, not merely shared activities.","related_words":["κοινός (koinos, G2839) — common, shared (14×)","κοινωνέω (koinōneō, G2841) — to share in, to participate (8×)","κοινωνός (koinōnos, G2844) — partner, participant (10×)"],"practice":[{"type":"identify","question":"What does κοινωνία (koinōnia) mean?","answer":"Fellowship / shared participation / partnership in something together"},{"type":"choice","question":"Acts 2:42 says the early church devoted themselves to four things. Which was one of them?","options":["Entertainment","κοινωνία (fellowship / shared life)","Political activism","Individual devotion only"],"answer":1},{"type":"choice","question":"In 1 Corinthians 10:16, Paul calls the Lord''s Supper the κοινωνία of Christ''s blood and body. What does this mean?","options":["A memorial only","A mystical participation in Christ''s death and life","A legal ceremony","A church tradition"],"answer":1}]}',
  '[{"ref":"Acts 2:42","text":"And they continued stedfastly in the apostles'' doctrine and fellowship, and in breaking of bread, and in prayers","note":"κοινωνία is one of the four pillars of the early church. Not a programme but a way of life — sharing everything in common under the apostles'' teaching"},{"ref":"1 John 1:3","text":"That which we have seen and heard declare we unto you, that ye also may have fellowship with us: and truly our fellowship is with the Father, and with his Son Jesus Christ","note":"κοινωνία begins vertically (with the Father and Son) and flows horizontally (with one another). We cannot have genuine fellowship with each other without first having it with God"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  38, 14, 'vocabulary', 'βαπτίζω — Baptize', 'G907 · 77 occurrences · Immerse & Identify',
  '{"word":"βαπτίζω","transliteration":"baptizō","meaning":"To baptize / immerse / plunge into","part_of_speech":"Verb","strongs":"G907","numeric_occurrences":77,"etymology":"From baptō meaning to dip, to plunge, to immerse in liquid. Used in secular Greek for dyeing cloth (the cloth was baptised in the dye — completely immersed). The NT uses it for water baptism and for Spirit baptism (baptism in the Holy Ghost, Acts 1:5).","theological_significance":"Baptism identifies the believer with Christ''s death and resurrection (Rom 6:3-4). The Great Commission commands baptism in the name of the Father, Son, and Holy Spirit (Matt 28:19). Baptism does not save (1 Pet 3:21 clarifies it is an appeal to God, not the washing of the flesh) but it is the public declaration of faith and entry into the visible church community.","related_words":["βάπτισμα (baptisma, G908) — baptism, the act (22×)","βαπτιστής (baptistēs, G910) — the Baptist (12×, title of John)","βαπτισμός (baptismos, G909) — washing, immersion (4×)"],"practice":[{"type":"identify","question":"What does βαπτίζω (baptizō) mean?","answer":"To baptize / to immerse / to plunge into"},{"type":"choice","question":"In secular Greek, βαπτίζω was used for dyeing cloth — plunging it into dye. What does this image suggest about Christian baptism?","options":["A gentle sprinkling","Total immersion — being completely identified with Christ","A formal ceremony only","A cleansing ritual"],"answer":1},{"type":"choice","question":"Romans 6:3-4 connects baptism to what two events in Christ''s life?","options":["Birth and ministry","Teaching and miracles","Death and resurrection","Suffering and ascension"],"answer":2}]}',
  '[{"ref":"Matthew 28:19","text":"Go ye therefore, and teach all nations, baptizing them in the name of the Father, and of the Son, and of the Holy Ghost","note":"βαπτίζοντες — baptizing. The Great Commission links disciple-making directly to baptism. The single Name (ὄνομα, singular) of three Persons is the first great trinitarian formula"},{"ref":"Romans 6:4","text":"Therefore we are buried with him by baptism into death: that like as Christ was raised up from the dead by the glory of the Father, even so we also should walk in newness of life","note":"Baptism (βαπτίσματος) as death and resurrection — the physical act enacts the spiritual reality. We go under the water as the old self; we rise as the new creation"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  39, 15, 'vocabulary', 'ἀπόστολος — Apostle', 'G652 · 81 occurrences · Sent one',
  '{"word":"ἀπόστολος","transliteration":"apostolos","meaning":"Apostle / sent one / commissioned messenger","part_of_speech":"Noun, masculine","strongs":"G652","numeric_occurrences":81,"etymology":"From apo (from) + stellō (to send). An apostle is one sent out with authority and a commission from another. In the Greek world it could describe a naval expedition or an ambassador. The NT uses it primarily for the Twelve and Paul — those personally commissioned by the risen Christ.","theological_significance":"The church is built on the foundation of the ἀπόστολοι and prophets (Eph 2:20). The Twelve were eyewitnesses of the resurrection — a qualification Paul met through the Damascus road encounter (1 Cor 9:1). Jesus Himself is called the Apostle (ἀπόστολον) of our confession (Heb 3:1) — the ultimate Sent One from the Father. Every Christian is sent (John 20:21).","related_words":["ἀποστέλλω (apostellō, G649) — to send, to commission (132×)","πέμπω (pempō, G3992) — to send (79×, more general sending)"],"practice":[{"type":"identify","question":"What does ἀπόστολος (apostolos) mean?","answer":"Apostle / sent one / commissioned messenger"},{"type":"choice","question":"ἀπόστολος comes from apo (from) + stellō (to send). What is the core idea?","options":["A teacher of the law","One sent out with authority and a commission","A church leader","A miracle worker"],"answer":1},{"type":"choice","question":"In John 20:21 Jesus says: As the Father has sent (ἀπέσταλκεν) me, even so send I you. What does this imply?","options":["Only the Twelve are sent","Every disciple shares in the apostolic sending","Apostles are a closed group","Sending requires ordination"],"answer":1}]}',
  '[{"ref":"Ephesians 2:20","text":"And are built upon the foundation of the apostles and prophets, Jesus Christ himself being the chief corner stone","note":"ἀποστόλων — apostles. Their teaching (now preserved in Scripture) is the foundation of the church. Christ is the cornerstone that holds it all together"},{"ref":"Hebrews 3:1","text":"Wherefore, holy brethren, partakers of the heavenly calling, consider the Apostle and High Priest of our profession, Christ Jesus","note":"Jesus is called the ἀπόστολον — the Sent One. He is both the ultimate apostle (sent by the Father) and the High Priest. The source of all Christian mission"}]'
);

-- ============================================
-- GROUP 4: KEY THEOLOGICAL TERMS (IDs 40–44)
-- ============================================

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  40, 16, 'vocabulary', 'λόγος — Word', 'G3056 · 330 occurrences · Divine reason made flesh',
  '{"word":"λόγος","transliteration":"logos","meaning":"Word / reason / divine expression / account","part_of_speech":"Noun, masculine","strongs":"G3056","numeric_occurrences":330,"etymology":"From legō meaning to speak or to reason. In Greek philosophy (especially the Stoics and Heraclitus), the logos was the rational principle ordering the universe — the cosmic mind behind reality. Philo of Alexandria, a Jewish philosopher, used logos as an intermediary between God and the world. John takes this entire tradition and declares: that logos is not an abstract principle — He is a Person, and He became flesh.","theological_significance":"The most theologically loaded word in John''s Gospel prologue. The logos was with God (relationship), was God (identity), was in the beginning (eternity), and became flesh (incarnation). The logos creates all things (John 1:3), contains all life (1:4), is the light of all humanity (1:4-5). Jesus IS the logos — the complete, final, personal self-expression of God.","related_words":["λέγω (legō, G3004) — to say, to speak (2354×)","λογίζομαι (logizomai, G3049) — to reckon, to count, to reason (41×)"],"practice":[{"type":"identify","question":"What does λόγος (logos) mean?","answer":"Word / reason / divine expression"},{"type":"choice","question":"John 1:14 says the logos became flesh. What was the significance of this for Greek readers?","options":["An ordinary man was born","The abstract rational principle of the universe became a human person","A new religion was started","God stopped being spirit"],"answer":1},{"type":"choice","question":"John 1:1 says the logos was with God (relationship) and was God (identity). What does this teach?","options":["Jesus is less than God","Jesus is separate from God","Jesus is fully God yet distinct from the Father — a trinitarian claim","Jesus became God at His baptism"],"answer":2}]}',
  '[{"ref":"John 1:1","text":"In the beginning was the Word, and the Word was with God, and the Word was God","note":"Ἐν ἀρχῇ ἦν ὁ λόγος — three statements in one verse: eternal (was in the beginning), relational (with God), and divine (was God). John deliberately echoes Genesis 1:1"},{"ref":"John 1:14","text":"And the Word was made flesh, and dwelt among us, and we beheld his glory","note":"ὁ λόγος σὰρξ ἐγένετο — the Word became flesh. The most staggering statement of the Incarnation. The abstract becomes concrete; the eternal becomes temporal; the infinite becomes finite"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  41, 17, 'vocabulary', 'δικαιοσύνη — Righteousness', 'G1343 · 92 occurrences · Being right with God',
  '{"word":"δικαιοσύνη","transliteration":"dikaiosynē","meaning":"Righteousness / justness / right standing / covenant faithfulness","part_of_speech":"Noun, feminine","strongs":"G1343","numeric_occurrences":92,"etymology":"From dikaios (just, righteous) and its root dike (right, justice). In Greek, dikaiosynē meant giving each person their due — legal and moral correctness. The NT deepens this: righteousness is relational conformity to God''s covenant character, and it is a gift imputed to believers through faith.","theological_significance":"The righteousness of God (δικαιοσύνη θεοῦ) is revealed in the gospel (Rom 1:17). This is not God''s punitive justice alone but His saving faithfulness — He acts to put things right. God made Christ to be sin for us that we might become the δικαιοσύνη of God in Him (2 Cor 5:21). We receive a righteousness not our own, from God, through faith in Christ (Phil 3:9).","related_words":["δίκαιος (dikaios, G1342) — righteous, just (79×)","δικαιόω (dikaioō, G1344) — to justify, to declare righteous (39×)","δικαίωσις (dikaiōsis, G1347) — justification (2×)"],"practice":[{"type":"identify","question":"What does δικαιοσύνη (dikaiosynē) mean?","answer":"Righteousness / right standing with God"},{"type":"choice","question":"Philippians 3:9 says Paul wants a righteousness not his own but from God through faith. This righteousness is:","options":["Earned by obedience","Imputed (credited) to us by faith — Christ''s righteousness given to us","Partially earned and partially given","Achieved by baptism"],"answer":1},{"type":"choice","question":"2 Corinthians 5:21 describes the great exchange. God made Christ to be sin so we might become:","options":["Holy in behaviour","The righteousness (δικαιοσύνη) of God in Him","Forgiven only","Morally perfect"],"answer":1}]}',
  '[{"ref":"Romans 1:17","text":"For therein is the righteousness of God revealed from faith to faith: as it is written, The just shall live by faith","note":"δικαιοσύνη θεοῦ — the righteousness of God. Paul''s thesis for the entire letter. This saving righteousness is the gift that changes everything"},{"ref":"2 Corinthians 5:21","text":"For he hath made him to be sin for us, who knew no sin; that we might be made the righteousness of God in him","note":"The great exchange: our sin to Christ; His δικαιοσύνη to us. The most compact statement of substitutionary atonement and imputed righteousness in the NT"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  42, 18, 'vocabulary', 'ἀλήθεια — Truth', 'G225 · 109 occurrences · Reality as God sees it',
  '{"word":"ἀλήθεια","transliteration":"alētheia","meaning":"Truth / reality / that which is real and not hidden","part_of_speech":"Noun, feminine","strongs":"G225","numeric_occurrences":109,"etymology":"From a (not) + lanthano (to be hidden or forgotten). Alētheia literally means un-hiddenness — that which is not concealed, reality as it actually is. In Platonic philosophy, truth was the realm of ideal Forms — ultimate reality. In the NT, truth is not abstract but personal: Jesus declares I am the truth (John 14:6).","theological_significance":"Pilate asked What is truth? (John 18:38) while Truth Himself stood before him. Jesus is the alētheia (John 14:6), the Word is alētheia (John 17:17), the Spirit is the Spirit of alētheia (John 16:13). True worship must be in Spirit and in alētheia (John 4:24). The truth sets free (John 8:32). Paul says the church is the pillar and ground of the alētheia (1 Tim 3:15).","related_words":["ἀληθής (alēthēs, G227) — true, truthful (26×)","ἀληθινός (alēthinos, G228) — genuine, real, authentic (28×)","ἀληθῶς (alēthōs, G230) — truly, really (18×)"],"practice":[{"type":"identify","question":"What does ἀλήθεια (alētheia) mean?","answer":"Truth / reality / that which is not hidden"},{"type":"choice","question":"Jesus declares in John 14:6: I am the way, the truth (ἀλήθεια), and the life. What does this mean for our understanding of truth?","options":["Truth is a philosophical concept","Truth is a set of rules","Truth is a Person — Jesus Himself","Truth is unknowable"],"answer":2},{"type":"choice","question":"John 8:32 promises: and ye shall know the truth (ἀλήθεια), and the truth shall make you ___.","options":["Wise","Happy","Free","Strong"],"answer":2}]}',
  '[{"ref":"John 14:6","text":"I am the way, the truth, and the life: no man cometh unto the Father, but by me","note":"ἡ ἀλήθεια — the truth (with the definite article: THE truth). Jesus is not one truth among many but THE definitive reality. All other truths are reflections of Him"},{"ref":"John 17:17","text":"Sanctify them through thy truth: thy word is truth","note":"ὁ λόγος ὁ σός ἀλήθειά ἐστιν — Your word is truth. Scripture is ἀλήθεια because it is the word of the God who is alētheia. Sanctification comes through the truth that the Word reveals"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  43, 19, 'vocabulary', 'δόξα — Glory', 'G1391 · 168 occurrences · Weighty splendour',
  '{"word":"δόξα","transliteration":"doxa","meaning":"Glory / honour / splendour / radiance","part_of_speech":"Noun, feminine","strongs":"G1391","numeric_occurrences":168,"etymology":"From dokeō meaning to seem, to appear, to give an impression. In classical Greek, doxa meant opinion or reputation — how one appeared to others. The NT transforms this through the Hebrew concept of kavod (weight, glory) — God''s glory is not merely His reputation but His actual weighty, luminous, overwhelming presence and splendour.","theological_significance":"God''s glory is His self-revelation — the radiant display of His character and presence. The Shekinah cloud was the glory of God made visible. Christ is the radiance (ἀπαύγασμα) of the Father''s glory (Heb 1:3). He showed His δόξα at the Transfiguration. We are saved to glorify God (Rom 15:7) and are being transformed into His glory from glory to glory (2 Cor 3:18). The goal of history is the manifestation of God''s δόξα filling all things.","related_words":["δοξάζω (doxazō, G1392) — to glorify, to honour (61×)","ἔνδοξος (endoxos, G1741) — glorious, honoured (4×)"],"practice":[{"type":"identify","question":"What does δόξα (doxa) mean?","answer":"Glory / honour / splendour"},{"type":"choice","question":"In Hebrews 1:3, Jesus is called the brightness/radiance of the Father''s δόξα. What does this mean?","options":["Jesus reflects some of God''s glory","Jesus is the exact and direct expression of the Father''s own glory","Jesus has less glory than the Father","Jesus received glory only after resurrection"],"answer":1},{"type":"choice","question":"Our English word doxology comes from δόξα + λόγος. What is a doxology?","options":["A word of prayer","A word of praise / an expression of glory to God","A word of confession","A word of teaching"],"answer":1}]}',
  '[{"ref":"John 17:5","text":"And now, O Father, glorify thou me with thine own self with the glory which I had with thee before the world was","note":"Jesus prays for the restoration of His pre-incarnate δόξα — the glory He shared with the Father in eternity. This is the strongest statement of Christ''s eternal pre-existence in the Gospels"},{"ref":"2 Corinthians 3:18","text":"But we all, with open face beholding as in a glass the glory of the Lord, are changed into the same image from glory to glory","note":"ἀπὸ δόξης εἰς δόξαν — from glory to glory. The Christian life is a progressive transformation INTO the δόξα of Christ. Beholding produces becoming"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  44, 20, 'vocabulary', 'ζωή — Life', 'G2222 · 135 occurrences · Eternal, God-quality life',
  '{"word":"ζωή","transliteration":"zōē","meaning":"Life (eternal / spiritual / God-quality life)","part_of_speech":"Noun, feminine","strongs":"G2222","numeric_occurrences":135,"etymology":"One of two Greek words for life: bios (biological/physical life, origin of biology) and zōē (spiritual, divine-quality life). Zōē is the life that belongs to God Himself and is shared with humanity through Christ. It is not mere survival but the fullness of divine existence.","theological_significance":"Jesus said I am come that they might have ζωή, and that they might have it more abundantly (John 10:10). I am the resurrection and the ζωή (John 11:25). God gave His Son so that everyone who believes should have αἰώνιος ζωή — eternal life (John 3:16). This life begins now (1 John 5:12-13) and extends into eternity. John wrote his Gospel so readers might have ζωή in Christ''s name (John 20:31).","related_words":["ζάω (zaō, G2198) — to live (140×)","αἰώνιος (aiōnios, G166) — eternal, age-lasting (71×, often with ζωή)","ζωοποιέω (zōopoieō, G2227) — to make alive, to give life (11×)"],"practice":[{"type":"identify","question":"What does ζωή (zōē) mean — and how does it differ from bios?","answer":"Zōē = spiritual, eternal, God-quality life; bios = biological/physical life"},{"type":"choice","question":"John 10:10 says Jesus came to give ζωή abundantly. What kind of life is this?","options":["A long physical life","Eternal / divine-quality life starting now","A life free from suffering","A life of service only"],"answer":1},{"type":"choice","question":"1 John 5:12 says He that hath the Son hath ζωή — and he that hath not the Son of God hath not ___. What?","options":["Salvation","Grace","Life (ζωή)","Hope"],"answer":2}]}',
  '[{"ref":"John 10:10","text":"I am come that they might have life, and that they might have it more abundantly","note":"ζωήν and περισσόν (more abundantly) — Jesus does not offer minimal survival. He offers overflowing, extravagant ζωή that exceeds all we could ask or imagine"},{"ref":"1 John 5:11–12","text":"And this is the record, that God hath given to us eternal life, and this life is in his Son. He that hath the Son hath life","note":"αἰώνιον ζωήν — eternal life. It is not earned or achieved; it is given. And it is entirely located in the Person of Christ — have the Son, have ζωή"}]'
);

-- ============================================
-- GROUP 5: ACTION WORDS (IDs 45–49)
-- ============================================

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  45, 21, 'vocabulary', 'πιστεύω — Believe', 'G4100 · 248 occurrences · The most important NT verb',
  '{"word":"πιστεύω","transliteration":"pisteuō","meaning":"To believe / to trust / to commit oneself to","part_of_speech":"Verb","strongs":"G4100","numeric_occurrences":248,"etymology":"The verb form of πίστις (faith). In Greek, pisteuo means to be persuaded of something, to put confidence in, to entrust oneself to. In the NT it is consistently followed by constructions meaning believe INTO Christ (πιστεύω εἰς) — not merely believe ABOUT Him, but entrust oneself TO Him.","theological_significance":"The most frequent verb in John''s Gospel (98 of its 248 NT occurrences). John specifically wrote his Gospel so that readers might believe (πιστεύω) that Jesus is the Christ and have life (John 20:31). Saving faith is πιστεύω εἰς — believe INTO, a total reliance. The 248 occurrences span every aspect of Christian life: beginning (John 3:16), continuing (John 8:31), and completing (Phil 1:6).","related_words":["πίστις (pistis, G4102) — faith (244×)","πιστός (pistos, G4103) — faithful, trustworthy (67×)","ἄπιστος (apistos, G571) — unbelieving (23×)"],"practice":[{"type":"identify","question":"What does πιστεύω (pisteuō) mean?","answer":"To believe / to trust / to commit oneself to"},{"type":"choice","question":"John often writes believe INTO Christ (πιστεύω εἰς). What does the preposition INTO add to the idea of believing?","options":["Nothing — it is the same as believing about","Active personal entrusting and commitment, not just mental agreement","Belief based on miracles only","Emotional certainty"],"answer":1},{"type":"choice","question":"How many times does πιστεύω appear in John''s Gospel alone?","options":["About 20","About 50","About 98","About 248"],"answer":2}]}',
  '[{"ref":"John 3:16","text":"For God so loved the world, that he gave his only begotten Son, that whosoever believeth in him should not perish, but have everlasting life","note":"πιστεύων εἰς αὐτόν — believing INTO Him. The promise is breathtaking in its inclusivity (whosoever) and its stakes (not perish vs everlasting life)"},{"ref":"John 20:31","text":"But these are written, that ye might believe that Jesus is the Christ, the Son of God; and that believing ye might have life through his name","note":"John''s purpose statement: πιστεύητε — that you might believe. The entire Gospel is written as an extended invitation to πιστεύω. Every sign, every discourse, every encounter leads here"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  46, 22, 'vocabulary', 'γινώσκω — Know', 'G1097 · 222 occurrences · Experiential knowledge',
  '{"word":"γινώσκω","transliteration":"ginōskō","meaning":"To know (through experience and relationship)","part_of_speech":"Verb","strongs":"G1097","numeric_occurrences":222,"etymology":"Greek has two main words for know: oida (to know as fact, intuitive or intellectual knowledge) and ginōskō (to know through experience, observation, relationship). Ginōskō is the knowing that comes from being in relationship — similar to the Hebrew yada which is used for the intimate knowing of husband and wife.","theological_significance":"John 17:3 defines eternal life: This is life eternal, that they might know (γινώσκωσιν) thee the only true God, and Jesus Christ. Eternal life is not a destination but a relationship — the ongoing knowing of God. Paul''s ambition: That I may know (γνῶναι) Him (Phil 3:10). Adam knew (ἔγνω) his wife Eve — same word. The knowledge God seeks is intimate, personal, and relational.","related_words":["οἶδα (oida, G1492) — to know (as fact / intellectually, 318×)","γνῶσις (gnōsis, G1108) — knowledge (29×)","ἐπίγνωσις (epignōsis, G1922) — full / complete knowledge (20×)"],"practice":[{"type":"identify","question":"What does γινώσκω (ginōskō) mean — and how does it differ from oida?","answer":"Ginōskō = experiential / relational knowing; oida = intellectual / factual knowing"},{"type":"choice","question":"John 17:3 defines eternal life as knowing (γινώσκωσιν) the Father and the Son. What kind of knowing is this?","options":["Memorising facts about God","Relational, experiential knowing — intimate fellowship with God","Theological study only","Obeying commandments"],"answer":1},{"type":"choice","question":"The Hebrew equivalent of γινώσκω is yada — used for the most intimate human relationship. What does this tell us about knowing God?","options":["It is purely academic","It is the deepest possible intimacy — more than information, a living relationship","It is only available to scholars","It requires special spiritual gifts"],"answer":1}]}',
  '[{"ref":"John 17:3","text":"And this is life eternal, that they might know thee the only true God, and Jesus Christ, whom thou hast sent","note":"γινώσκωσιν — that they might know (ongoing, experiential knowing). Eternal life IS the knowing of God — not just a reward for knowing facts but the relational experience of God Himself"},{"ref":"Philippians 3:10","text":"That I may know him, and the power of his resurrection, and the fellowship of his sufferings","note":"τοῦ γνῶναι αὐτόν — to know Him. Paul''s supreme ambition. After his Damascus road encounter, after years of apostolic ministry, he still longs for deeper γινώσκω of Christ"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  47, 23, 'vocabulary', 'ἀγαπάω — Love', 'G25 · 143 occurrences · Love as a choice',
  '{"word":"ἀγαπάω","transliteration":"agapaō","meaning":"To love (unconditionally, by choice, as God loves)","part_of_speech":"Verb","strongs":"G25","numeric_occurrences":143,"etymology":"The verb form of ἀγάπη. Like its noun form, this verb was rarely used before the NT and was largely redefined by Christian usage. It emphasises love as a decision and action — not primarily an emotion. God so ἠγάπησεν (loved, verb) the world that He GAVE. The love is demonstrated in the giving.","theological_significance":"The greatest commandment is to ἀγαπάω God and neighbour (Matt 22:37-39). The new commandment is to ἀγαπάω one another as Christ has loved us (John 13:34). The verb tense matters: ἀγαπάτε (present imperative) = keep on loving, love continuously. After the resurrection, Jesus asked Peter three times Dost thou love me (ἀγαπᾷς με vs φιλεῖς με) — the famous exchange exploring the nature of Peter''s love.","related_words":["ἀγάπη (agapē, G26) — love (noun, 116×)","φιλέω (phileō, G5368) — to love as a friend, to have affection (25×)","στέργω (stergō) — to love as family (not in NT but related concept)"],"practice":[{"type":"identify","question":"What does ἀγαπάω (agapaō) mean?","answer":"To love (unconditionally, by choice — the verb form of agapē)"},{"type":"choice","question":"In John 21, Jesus asks Peter Dost thou love (ἀγαπᾷς) me? Then Peter says Lord, thou knowest that I love (φιλῶ) thee. What is Peter using — the same word or a different one?","options":["The same word each time","A different word — Peter shifts to phileō (friendship love), possibly unable to claim the full agapaō","Both mean exactly the same thing","The difference is just stylistic"],"answer":1},{"type":"choice","question":"The new commandment (John 13:34) is to ἀγαπᾶτε (present imperative: keep on loving) one another. The standard for this love is:","options":["As you love yourself","As a family loves","As I (Christ) have loved you","As the law commands"],"answer":2}]}',
  '[{"ref":"John 13:34","text":"A new commandment I give unto you, That ye love one another; as I have loved you, that ye also love one another","note":"ἀγαπᾶτε — keep on loving. The standard is Christ''s own love (ἠγάπησα). This is not the law''s standard (love your neighbour as yourself) but an impossibly higher one: as I have loved you"},{"ref":"Romans 5:8","text":"But God commendeth his love toward us, in that, while we were yet sinners, Christ died for us","note":"ἀγάπην ἑαυτοῦ — His own love. God''s ἀγαπάω is demonstrated in the most extreme circumstance: loving the unlovable, dying for the ungrateful. This is the definition of agapē in action"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  48, 24, 'vocabulary', 'μετανοέω — Repent', 'G3340 · 34 occurrences · Change of mind and direction',
  '{"word":"μετανοέω","transliteration":"metanoeō","meaning":"To repent / to change one''s mind / to turn around","part_of_speech":"Verb","strongs":"G3340","numeric_occurrences":34,"etymology":"From meta (change, after) + noeō (to think, from nous, mind). Repentance is literally a change of mind — a fundamental reorientation of thinking that leads to a change of direction. It is not merely feeling sorry (that is sorrow, lypē) but a decisive mental and volitional turn toward God and away from sin.","theological_significance":"The first word of both John the Baptist''s preaching and Jesus'' public ministry: μετανοεῖτε (Matt 3:2, 4:17). The first sermon of the church at Pentecost calls for repentance (Acts 2:38). True repentance involves three elements: intellectual (changing one''s understanding of sin and God), emotional (genuine sorrow, 2 Cor 7:10), and volitional (turning around — demonstrated by changed behaviour). God''s kindness leads to repentance (Rom 2:4).","related_words":["μετάνοια (metanoia, G3341) — repentance (noun, 22×)","μεταμέλομαι (metamelomai, G3338) — to regret, to feel remorse (6×, different from true repentance)"],"practice":[{"type":"identify","question":"What does μετανοέω (metanoeō) mean?","answer":"To repent — to change one''s mind and direction, to turn toward God"},{"type":"choice","question":"μετανοέω comes from meta (change) + noeō (to think). What part of the person does repentance primarily involve?","options":["The emotions only","The mind / thinking — leading to a change of direction","The body through fasting","The will only"],"answer":1},{"type":"choice","question":"What was the first word of both John the Baptist''s and Jesus'' public preaching?","options":["Love","Believe","Repent (μετανοεῖτε)","Pray"],"answer":2}]}',
  '[{"ref":"Matthew 4:17","text":"From that time Jesus began to preach, and to say, Repent: for the kingdom of heaven is at hand","note":"μετανοεῖτε — repent (present imperative: keep repenting, make it a lifestyle). Jesus begins His public ministry with this call. Repentance is the gateway to the kingdom"},{"ref":"Acts 2:38","text":"Then Peter said unto them, Repent, and be baptized every one of you in the name of Jesus Christ for the remission of sins, and ye shall receive the gift of the Holy Ghost","note":"μετανοήσατε — repent (aorist imperative: do it now, decisively). The first call of the church after Pentecost. μετανοέω leads to βαπτίζω leads to receiving the πνεῦμα"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  49, 25, 'vocabulary', 'δοξάζω — Glorify', 'G1392 · 61 occurrences · Giving weight to God',
  '{"word":"δοξάζω","transliteration":"doxazō","meaning":"To glorify / to honour / to magnify / to give praise","part_of_speech":"Verb","strongs":"G1392","numeric_occurrences":61,"etymology":"The verb form of δόξα (glory). To glorify God means to acknowledge His true weight and worth — to ascribe to Him the glory due His name. It is the proper response of the creature to the Creator. The opposite is to rob God of His δόξα or to give it to something else (Rom 1:21-23).","theological_significance":"The chief end of human existence: to glorify God and enjoy Him forever (Westminster Catechism paraphrase of 1 Cor 10:31). Jesus glorified the Father through His works (John 17:4) and the Father glorified the Son through resurrection (John 13:31-32). We glorify God by bearing fruit (John 15:8), by our bodies (1 Cor 6:20), and by every word and action (1 Cor 10:31). The Holy Spirit glorifies the Son (John 16:14).","related_words":["δόξα (doxa, G1391) — glory (168×)","ἐνδοξάζω (endoxazō, G1740) — to glorify in (2 Thess 1:10,12)","συνδοξάζω (syndoxazō, G4888) — to be glorified with (Rom 8:17)"],"practice":[{"type":"identify","question":"What does δοξάζω (doxazō) mean?","answer":"To glorify / to honour God / to ascribe glory to Him"},{"type":"choice","question":"1 Corinthians 10:31 says: Whether therefore ye eat, or drink, or whatsoever ye do, do all to the δόξα of God. What does this mean practically?","options":["Only religious activities glorify God","Every ordinary action can and should glorify God","Glorifying God requires special spiritual gifts","Only worship services count"],"answer":1},{"type":"choice","question":"In John 17:4, Jesus says He glorified the Father by doing what?","options":["Performing miracles only","Finishing the work the Father gave Him","Preaching only","Gathering disciples"],"answer":1}]}',
  '[{"ref":"John 17:4","text":"I have glorified thee on the earth: I have finished the work which thou gavest me to do","note":"δεδόξακά σε — I have glorified You. Jesus'' life was a complete act of δοξάζω — every moment, every healing, every word pointed to the Father''s glory. This is the model for our lives"},{"ref":"1 Peter 4:11","text":"If any man speak, let him speak as the oracles of God; if any man minister, let him do it as of the ability which God giveth: that God in all things may be glorified through Jesus Christ","note":"δοξάζηται ὁ θεός — that God may be glorified. Ministry, teaching, serving — all are channels of δοξάζω. The test of every activity is: does this make God look glorious?"}]'
);

