-- GROUP 6: PROPHECY & END TIMES (IDs 50–54)
-- ============================================

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  50, 26, 'vocabulary', 'παρουσία — Coming', 'G3952 · 24 occurrences · The royal arrival',
  '{"word":"παρουσία","transliteration":"parousia","meaning":"Coming / arrival / presence / royal visit","part_of_speech":"Noun, feminine","strongs":"G3952","numeric_occurrences":24,"etymology":"From para (beside, alongside) + ousia (being, essence — from eimi, to be). Literally: the being-alongside, the presence. In the Hellenistic world, parousia was the technical term for the official visit of a king or emperor to a city. The city would prepare in advance, go out to meet him, and escort him back. The NT uses exactly this imagery for Christ''s return.","theological_significance":"The Second Coming of Christ is His royal παρουσία — His official royal visit to earth as King. Used 24 times in the NT, primarily by Paul and in Matthew 24. The four features of the parousia: suddenness (1 Thess 5:2), glory (Matt 24:27), gathering of the elect (Matt 24:31), and judgment (2 Thess 2:8). Paul comforts bereaved believers by pointing to the παρουσία (1 Thess 4:15-17).","related_words":["ἀποκάλυψις (apokalypsis, G602) — revelation, unveiling (18×)","ἐπιφάνεια (epiphaneia, G2015) — appearing, manifestation (6×)","ἔρχομαι (erchomai, G2064) — to come (636×)"],"practice":[{"type":"identify","question":"What does παρουσία (parousia) mean?","answer":"Coming / royal arrival / presence — the Second Coming of Christ"},{"type":"choice","question":"In the Hellenistic world, parousia was used for the official visit of a king. How does this background enrich Matthew 24 and 1 Thessalonians 4?","options":["It shows the second coming is unexpected","It shows the second coming is a royal event with cosmic preparation and a procession to meet the King","It shows the second coming is only for Jews","It shows the second coming is invisible"],"answer":1},{"type":"choice","question":"1 Thessalonians 4:15-17 uses παρουσία to comfort those grieving. What is the comfort?","options":["The dead are in heaven already","At the παρουσία, the dead in Christ rise first, then the living are caught up together with them","Death is not real","The second coming already happened"],"answer":1}]}',
  '[{"ref":"Matthew 24:27","text":"For as the lightning cometh out of the east, and shineth even unto the west; so shall also the coming of the Son of man be","note":"παρουσία — the coming. Sudden, universal, unmistakable — like lightning across the whole sky. No one will miss the παρουσία of the Son of Man"},{"ref":"1 Thessalonians 4:15","text":"For this we say unto you by the word of the Lord, that we which are alive and remain unto the coming of the Lord shall not prevent them which are asleep","note":"παρουσίαν τοῦ κυρίου — the royal arrival of the Lord. Paul''s great comfort to grieving believers: death does not end the story; the παρουσία completes it"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  51, 27, 'vocabulary', 'ἀποκάλυψις — Revelation', 'G602 · 18 occurrences · The great unveiling',
  '{"word":"ἀποκάλυψις","transliteration":"apokalypsis","meaning":"Revelation / unveiling / disclosure","part_of_speech":"Noun, feminine","strongs":"G602","numeric_occurrences":18,"etymology":"From apo (away from) + kalyptō (to cover, to veil). Apokalypsis is the removing of a veil — an unveiling of what was previously hidden. The last book of the Bible takes its name from this word (The Revelation of John) because it is the great unveiling of what God is doing in history.","theological_significance":"The book of Revelation opens: The ἀποκάλυψις of Jesus Christ (Rev 1:1) — it is a revelation OF Christ, not merely about Him. Paul speaks of the ἀποκάλυψις of the righteous judgment of God (Rom 2:5) and of the sons of God (Rom 8:19). The gospel itself is a divine ἀποκάλυψις — God pulling back the veil to show His saving purpose hidden from ages (Eph 3:3-5).","related_words":["ἀποκαλύπτω (apokalyptō, G601) — to reveal, to unveil (26×)","καλύπτω (kalyptō, G2572) — to cover, to veil (8×)","φανερόω (phaneroō, G5319) — to make visible, to manifest (49×)"],"practice":[{"type":"identify","question":"What does ἀποκάλυψις (apokalypsis) mean?","answer":"Revelation / unveiling — the removing of a covering to reveal what was hidden"},{"type":"choice","question":"The book of Revelation is called ἀποκάλυψις Ἰησοῦ Χριστοῦ (Rev 1:1). It is primarily a revelation OF what?","options":["Future events","The church''s history","Jesus Christ Himself — His person, His reign, His victory","The end of the world"],"answer":2},{"type":"choice","question":"Romans 8:19 says creation waits for the ἀποκάλυψις of the sons of God. What is this?","options":["The final judgment of sinners","The glorious unveiling of believers in resurrection glory — which will trigger the renewal of all creation","The return of Israel","The rapture alone"],"answer":1}]}',
  '[{"ref":"Revelation 1:1","text":"The Revelation of Jesus Christ, which God gave unto him, to shew unto his servants things which must shortly come to pass","note":"ἀποκάλυψις Ἰησοῦ Χριστοῦ — the great unveiling. The entire book peels back the curtain between visible and invisible reality to show Christ reigning over all of history"},{"ref":"Romans 8:19","text":"For the earnest expectation of the creature waiteth for the manifestation of the sons of God","note":"ἀποκάλυψιν τῶν υἱῶν τοῦ θεοῦ — the unveiling of God''s sons. All creation holds its breath for the moment when believers are glorified — a cosmic ἀποκάλυψις that renews everything"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  52, 28, 'vocabulary', 'βασιλεία — Kingdom', 'G932 · 162 occurrences · The reign of God',
  '{"word":"βασιλεία","transliteration":"basileia","meaning":"Kingdom / reign / rule / royal domain","part_of_speech":"Noun, feminine","strongs":"G932","numeric_occurrences":162,"etymology":"From basileus meaning king. Basileia is both the realm of a king and the act of his reigning — not just a territory but a dynamic rule. The Kingdom of God is wherever and whenever God''s sovereign will is being done.","theological_significance":"The central theme of Jesus'' preaching. The Synoptic Gospels record kingdom language constantly. The Kingdom is both present (Luke 17:21, the kingdom is within/among you) and future (Matt 6:10, thy kingdom come). It is entered through new birth (John 3:3,5), through repentance and faith (Mark 1:15), and through the Spirit (Rom 14:17). The Sermon on the Mount is the constitution of the Kingdom. The Lord''s Prayer is the Kingdom prayer. Revelation closes with the Kingdom fully arrived.","related_words":["βασιλεύς (basileus, G935) — king (115×)","βασιλεύω (basileuō, G936) — to reign, to be king (21×)","βασίλισσα (basilissa, G938) — queen (4×)"],"practice":[{"type":"identify","question":"What does βασιλεία (basileia) mean?","answer":"Kingdom / reign / rule of God"},{"type":"choice","question":"Jesus said the βασιλεία of God is both present and future. Which verse shows it is PRESENT?","options":["Matthew 6:10 (thy kingdom come)","Luke 17:21 (the kingdom of God is within/among you)","Matthew 25:34 (come ye blessed, inherit the kingdom)","Revelation 11:15 (the kingdoms of this world are become the kingdoms of our Lord)"],"answer":1},{"type":"choice","question":"Romans 14:17 defines the βασιλεία of God as consisting of what three things?","options":["Prayer, fasting, and giving","Righteousness, peace, and joy in the Holy Spirit","Miracles, signs, and wonders","Love, faith, and hope"],"answer":1}]}',
  '[{"ref":"Matthew 6:10","text":"Thy kingdom come. Thy will be done in earth, as it is in heaven","note":"βασιλεία σου — Your kingdom. The Lord''s Prayer is fundamentally a Kingdom prayer. God''s reign coming means His will being done — the two are inseparable"},{"ref":"Mark 1:15","text":"The time is fulfilled, and the kingdom of God is at hand: repent ye, and believe the gospel","note":"ἡ βασιλεία τοῦ θεοῦ — the Kingdom of God. Jesus'' first public sermon in Mark. Repentance and faith are the entry requirements. The Kingdom has arrived in the Person of the King"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  53, 29, 'vocabulary', 'κρίσις — Judgment', 'G2920 · 48 occurrences · The final evaluation',
  '{"word":"κρίσις","transliteration":"krisis","meaning":"Judgment / evaluation / decision / justice","part_of_speech":"Noun, feminine","strongs":"G2920","numeric_occurrences":48,"etymology":"From krinō meaning to separate, to distinguish, to judge, to decide. Krisis is the act of discernment — separating and evaluating. Our word crisis comes directly from Greek (a crisis is a turning point requiring a decisive judgment). In the NT, krisis is primarily God''s final evaluation of all human actions and choices.","theological_significance":"It is appointed for humans to die once, and after that comes krisis (Heb 9:27). The Father has committed all krisis to the Son (John 5:22). The standard of krisis is the word of Christ — His λόγος will judge at the last day (John 12:48). The outcome of krisis is eternal life or second death. Believers stand before the Bema Seat (judgment seat) for rewards (2 Cor 5:10); unbelievers face the Great White Throne (Rev 20:11-15).","related_words":["κρίνω (krinō, G2919) — to judge, to evaluate (114×)","κριτής (kritēs, G2923) — judge (19×)","κατακρίνω (katakrinō, G2632) — to condemn, to judge against (18×)"],"practice":[{"type":"identify","question":"What does κρίσις (krisis) mean?","answer":"Judgment / evaluation / a decisive separation"},{"type":"choice","question":"John 5:22 says the Father has committed all judgment (κρίσιν) to the Son. What will the standard of that judgment be?","options":["The Mosaic Law","How much a person suffered","The word (λόγος) of Christ (John 12:48)","Human moral effort"],"answer":2},{"type":"choice","question":"Hebrews 9:27 says it is appointed for humans to die once, then comes κρίσις. What does this deny?","options":["Heaven","Resurrection","Reincarnation and purgatory (no second chance after death)","Prayer for the dead"],"answer":2}]}',
  '[{"ref":"John 5:22","text":"For the Father judgeth no man, but hath committed all judgment unto the Son","note":"πᾶσαν τὴν κρίσιν — all the judgment. The authority of final evaluation rests entirely with Christ. Every human being will stand before the One they either received or rejected"},{"ref":"Hebrews 9:27","text":"And as it is appointed unto men once to die, but after this the judgment","note":"κρίσις — after death comes judgment. The most sobering κρίσις verse: one life, one death, one judgment. No cycle of reincarnation, no second chance. The urgency of the gospel rests on this fact"}]'
);

INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  54, 30, 'vocabulary', 'αἰώνιος — Eternal', 'G166 · 71 occurrences · Age-lasting life',
  '{"word":"αἰώνιος","transliteration":"aiōnios","meaning":"Eternal / everlasting / age-lasting / of the Age to Come","part_of_speech":"Adjective","strongs":"G166","numeric_occurrences":71,"etymology":"From aiōn meaning age or era (not just time in general, but a significant epoch). Aiōnios describes that which belongs to or partakes of the Age to Come — the coming eternal order. In John''s Gospel especially, eternal life is not just unending duration but a quality of life belonging to the divine realm.","theological_significance":"The most important modifier in the NT: αἰώνιος ζωή (eternal life, 43 of its 71 occurrences). This life begins the moment of belief (John 5:24: has — present tense — eternal life) and never ends. Jesus defines it relationally: knowing God and Christ (John 17:3). Αἰώνιος also describes eternal punishment (Matt 25:46), eternal judgment (Heb 6:2), and eternal glory (2 Cor 4:17). The Age to Come has already broken into the present through Christ.","related_words":["αἰών (aiōn, G165) — age, era, eternity (122×)","ζωή αἰώνιος — eternal life (the phrase, most important usage)"],"practice":[{"type":"identify","question":"What does αἰώνιος (aiōnios) mean?","answer":"Eternal / everlasting / belonging to the Age to Come"},{"type":"choice","question":"John 5:24 says the one who believes HAS (present tense) eternal life. What does the present tense tell us?","options":["Eternal life is only a future promise","Eternal life begins at death","Eternal life begins NOW at the moment of belief","Eternal life is conditional on continued obedience"],"answer":2},{"type":"choice","question":"John 17:3 defines αἰώνιος ζωή as what?","options":["Going to heaven when you die","Knowing God the Father and Jesus Christ whom He sent","Following the commandments","Being born again"],"answer":1}]}',
  '[{"ref":"John 3:16","text":"That whosoever believeth in him should not perish, but have everlasting life","note":"ζωὴν αἰώνιον — everlasting life. The most famous promise in Scripture hinges on αἰώνιος. Not just endless life but the rich, full, divine-quality life that belongs to the Age to Come"},{"ref":"Matthew 25:46","text":"And these shall go away into everlasting punishment: but the righteous into life eternal","note":"κόλασιν αἰώνιον... ζωὴν αἰώνιον — the same adjective αἰώνιος applies to both outcomes. The same eternity awaits all — either in blessing or in judgment. The word makes both permanent."}]'
);

